const d = $input.first().json;
const date = d.date;
const summary = d.today_summary;
const projects = (d.projects || []).join('
');
const resolved = d.resolved_today.map(i => `  ✅ ${i.exec_id}: ${i.title}`).join('
') || '  None';
const pending = d.still_pending.map(i => `  ⏳ ${i.exec_id}: ${i.title}`).join('
') || '  None';
const complete = (d.missions?.complete || []).map(m => `  ✅ ${m}`).join('
') || '  None';
const blocked = (d.missions?.blocked || []).map(m => `  🚫 ${m}`).join('
') || '  None';
const overnight = (d.overnight_plan || []).join('
  ');

const body = `HCI AI — End of Day Brief
${date}

` +
  `SUMMARY
` +
  `  Mining runs today: ${summary.mining_runs}
` +
  `  Decisions resolved: ${summary.decisions_resolved}
` +
  `  Decisions pending: ${summary.decisions_pending}
` +
  `  Hours saved this week: ${d.roi_hours_this_week}h

` +
  `PROJECTS
${projects}

` +
  `RESOLVED TODAY
${resolved}

` +
  `STILL PENDING
${pending}

` +
  `MISSIONS
  Complete:
${complete}
  Blocked:
${blocked}

` +
  `OVERNIGHT PLAN
  ${overnight}

` +
  `Dashboard: http://localhost:8000/executive`;

return [{ json: { subject: `HCI AI EOD — ${date}`, body } }];
